// Genera items para las páginas 1-10 de Trustpilot
// (cobertura amplia — las vacías se ignoran en el parseo)
const items = [];
for (let p = 1; p <= 10; p++) {
  items.push({ json: { page: p } });
}
return items;

// Extrae reviews del __NEXT_DATA__ de TODAS las páginas recibidas
// FIX: antes usaba $input.first() que solo procesaba la página 1
const allItems = $input.all();
const allReviews = [];

for (const item of allItems) {
  // El HTTP Request con responseFormat:text devuelve el body en item.json.data
  const html = typeof item.json === 'string'
    ? item.json
    : (item.json.data ?? item.json.body ?? '');

  if (typeof html !== 'string' || html.length < 500) continue;

  const match = html.match(/<script id="__NEXT_DATA__" type="application\/json">([\s\S]*?)<\/script>/);
  if (!match) continue;

  let data;
  try { data = JSON.parse(match[1]); } catch { continue; }

  const rawReviews = data?.props?.pageProps?.reviews;
  if (!Array.isArray(rawReviews) || rawReviews.length === 0) continue;

  const reviews = rawReviews
    .map(r => ({
      trustpilot_id: r.id,
      reviewer_name: r.consumer?.displayName ?? 'Anónimo',
      stars: r.rating,
      review_date: r.dates?.publishedDate ?? new Date().toISOString(),
      headline: r.title ?? '',
      review_body: r.text ?? ''
    }))
    .filter(r => r.trustpilot_id && r.stars >= 1 && r.stars <= 5);

  allReviews.push(...reviews);
}

return [{ json: { reviews: allReviews, count: allReviews.length } }];

const SUPABASE_URL = 'https://cgbezrwywsgkidssptfm.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNnYmV6cnd5d3Nna2lkc3NwdGZtIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDkzMjEwNiwiZXhwIjoyMDg2NTA4MTA2fQ.Yg5UdP38UyAq-QQLVxBJLbNmAXArSDlLzMvtZ1QdnTY';

// Recoge todas las reviews del nodo anterior
const allItems = $input.all();
const allReviews = [];
for (const item of allItems) {
  if (Array.isArray(item.json.reviews)) allReviews.push(...item.json.reviews);
}

// Deduplicar por trustpilot_id
const seen = new Set();
const unique = allReviews.filter(r => {
  if (!r.trustpilot_id || seen.has(r.trustpilot_id)) return false;
  seen.add(r.trustpilot_id);
  return true;
});

if (unique.length === 0) {
  return [{ json: { ok: true, message: 'No reviews scraped (Trustpilot may have blocked)', scraped: 0, upserted: 0 } }];
}

// Upsert en lotes de 50 con on-conflict trustpilot_id
const BATCH = 50;
let upserted = 0;
for (let i = 0; i < unique.length; i += BATCH) {
  const batch = unique.slice(i, i + BATCH);
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/trustpilot_reviews?on_conflict=trustpilot_id`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'resolution=merge-duplicates,return=minimal',
    },
    body: JSON.stringify(batch),
    returnFullResponse: true,
  });
  if (res.statusCode >= 400) {
    throw new Error(`Supabase upsert failed: ${res.statusCode} — ${JSON.stringify(res.body)}`);
  }
  upserted += batch.length;
}

return [{ json: {
  ok: true,
  scraped: unique.length,
  upserted,
  syncedAt: new Date().toISOString()
} }];
